"use client"

import { useState } from "react"

import { CodeBlockFrame } from "./CodeBlockFrame"

interface CodeExampleClientProps {
  language?: string
  filename?: string
  filepath: string
  snippet: string
  fullCode: string
  snippetHtml: string
  fullCodeHtml: string
  snippetTitle?: string
  fullFileTitle?: string
}

function formatLanguage(language?: string): string {
  if (!language) return "TEXT"
  return language.toUpperCase()
}

export function CodeExampleClient({
  language = "ts",
  filename,
  filepath,
  snippet,
  fullCode,
  snippetHtml,
  fullCodeHtml,
  snippetTitle = "Focused extract",
  fullFileTitle = "Full file",
}: CodeExampleClientProps) {
  const [expanded, setExpanded] = useState(false)
  const [copied, setCopied] = useState(false)

  const displayedCode = expanded ? fullCode : snippet

  async function handleCopy() {
    await navigator.clipboard.writeText(displayedCode)
    setCopied(true)

    window.setTimeout(() => {
      setCopied(false)
    }, 1500)
  }

  return (
    <div className="my-8 overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
      <div className="sticky top-0 z-20 border-b border-white/10 bg-[#12141a]/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-[#12141a]/80">
        <div className="flex items-start justify-between gap-4">
          <div className="min-w-0">
            <div className="truncate text-sm font-medium text-white">
              {snippetTitle}
            </div>
          </div>

          <div className="flex shrink-0 items-center gap-2">
            <span className="rounded-md border border-white/10 bg-white/[0.04] px-2 py-1 text-[11px] font-medium tracking-wide text-white/70">
              {formatLanguage(language)}
            </span>

            <button
              type="button"
              onClick={handleCopy}
              className="rounded-md border border-white/10 bg-white/[0.04] px-3 py-1 text-xs text-white/70 transition-colors hover:bg-white/[0.07] hover:text-white"
            >
              {copied ? "Copied" : "Copy"}
            </button>
          </div>
        </div>

        <div className="mt-2 flex items-center justify-between gap-4">
          <div className="min-w-0 truncate text-xs text-white/45">
            {filepath}
          </div>

          <button
            type="button"
            onClick={() => setExpanded((value) => !value)}
            className="shrink-0 rounded-md border border-white/10 bg-white/[0.04] px-3 py-1 text-xs text-white/70 transition-colors hover:bg-white/[0.07] hover:text-white"
          >
            {expanded ? "Revenir à l’extrait" : "Voir le fichier complet"}
          </button>
        </div>
      </div>

      <div className="max-h-[70vh] overflow-auto">
        {expanded ? (
          <CodeBlockFrame html={fullCodeHtml} />
        ) : (
          <CodeBlockFrame html={snippetHtml} />
        )}
      </div>
    </div>
  )
}

export default CodeExampleClient